import React, { useState, useEffect, useCallback, useRef } from 'react';
import { useParams } from 'react-router-dom';
import Swal from 'sweetalert2';
import { useSocket } from '../../useSocket';
import { getDistance } from 'geolib';

import { joinApi } from '../../apiBase';
import Header from './Header';
import Table from './Table';
import Add from './Add';
import Edit from './Edit';

const Dashboard = ({ isAuthenticated, setIsAuthenticated, setShowLogin }) => {
  const { court_abbrev } = useParams();
  // Use route param directly as abbreviation
  const abbreviation = court_abbrev ? court_abbrev.toUpperCase() : '';

  const [courts, setCourts] = useState([]);
  const [selectedCourt, setselectedCourt] = useState(null);
  const [isAdding, setIsAdding] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [timers, setTimers] = useState({});
  const [searchQuery, setSearchQuery] = useState('');

  const timerIdsRef = useRef({});
  const isSubmittingRef = useRef(false);

  const fetchCourtsData = useCallback(async () => {
    try {
      let url = joinApi('/api/tables');
      if (abbreviation) {
        url += `?abbreviation=${abbreviation}`;
      }
      let popularUrl = joinApi('/api/popular');
      if (abbreviation) {
        popularUrl += `?abbreviation=${abbreviation}`;
      }

      const [res, popularRes] = await Promise.all([
        fetch(url),
        fetch(popularUrl)
      ]);
      const data = await res.json();
      const popularData = await popularRes.json();
      console.log('Fetched data:', data); // Check the structure of the response

      let rows = data.tables || [];
      const popularRows = popularData.popular_times || [];
      const popularTimesByCourt = popularRows.reduce((acc, row) => {
        const courtAbbrev = row.court_abbrev?.toUpperCase();
        if (!courtAbbrev) return acc;
        if (!acc[courtAbbrev]) acc[courtAbbrev] = [];
        acc[courtAbbrev].push(row);
        return acc;
      }, {});

      console.log('Rows:', rows); // Check the rows being processed
      const courtsMap = {};
      rows.forEach(row => {
        courtsMap[row.id] = {
          id: row.id,
          court_name: row.court_name,
          address: row.address,
          court_capacity: row.court_capacity,
          max_mins: row.max_mins,
          max_meters: row.max_meters,
          latitude: row.latitude,
          longitude: row.longitude,
          occupied: row.occupied || 0, //this is fine
          court_labels: row.court_labels || [],
          recent_times: row.recent_times || [],
          today_times: row.today_times || [],
          popular_times: popularTimesByCourt[row.court_abbrev?.toUpperCase()] || [],
          court_abbrev: row.court_abbrev,
          enable_geofence: row.enable_geofence,
          timezone: row.timezone,
          display_time_type: row.display_time_type,
          solo_notes: row.solo_notes || [],
          all_notes: row.all_notes || [],
        };
      });
      let courtsData = Object.values(courtsMap);
      setCourts(courtsData); // Always set raw courts data
    } catch (error) {
      setCourts([]);
    }
  }, [abbreviation]);

  // good functions, order matters

  const swalError = (message) => {
    Swal.fire({
      icon: 'error',
      title: 'Error!',
      text: message,
      showConfirmButton: false,
      showCloseButton: true,
      timer: 10000
    });
  }
  
  //updating court functions
  const updateRequest = useCallback(async(court_abbrev, court_label, distance) => {
    try {
      if (!localStorage.getItem('anon_token')) {
        localStorage.setItem('anon_token', crypto.randomUUID());
      }
      const anon_token = localStorage.getItem('anon_token');

      await fetch(joinApi(`/api/tables/${court_abbrev}/occupied`), { //join api in apiBase.js
        method: 'PUT',
        headers: { 'Content-Type': 'application/json', },
        body: JSON.stringify({ abbrev: court_abbrev, label: court_label, distance: distance, client_dt: new Date().toISOString(), anon_token: anon_token }) //has to be body not params
      });
    }catch(error) {
      console.error('Error sending update request:', error);
      swalError('Failed to send update request. Please try again.');
    }
  }, []);
  
  const updateCourts = useCallback(async (court, court_label, distance) => {
    try {
      await updateRequest(court.court_abbrev, court_label, distance);
      await fetchCourtsData();
  
      const allowedUsageTime = court.max_mins * 60000;
  
      const startTime = Date.now();
      const expireTime = startTime + allowedUsageTime;
      const extraTime = window.location.hostname === 'localhost' || window.location.hostname === 'test.courtinuse.com' ? 10000 : 1800000;
  
      const newTimers = { ...timers, [court.id]: { startTime, expireTime, extraTime } };
  
      setTimers(newTimers);
      localStorage.setItem('courtTimers', JSON.stringify(newTimers));
  
      Swal.fire({
        icon: 'success',
        title: 'Enjoy!',
        html: `
          <div>
            Limit playing time to 30 minutes when others are waiting.
            <br/><br/>
            Courts are displayed as occupied for 1 hour after a scan.
          </div>
        `,
        showConfirmButton: false,
        timer: 10000,
        showCloseButton: true,
      });
  
      setTimeout(async () => {
        Swal.fire({
          icon: 'info',
          title: 'Court Time Expired',
          text: 'Your court time is up. Please let others play if they are waiting.',
          showConfirmButton: false,
          showCloseButton: true,
          timer: 10000
        });

        await fetchCourtsData(); //refresh the data, mainly for the occupancy
      }, expireTime - Date.now());

      setTimeout(async () => {
        setTimers(prev => {
          const updated = { ...prev };
          delete updated[court.id];

          localStorage.setItem('courtTimers', JSON.stringify(updated));
          return updated;
        });
      }, expireTime + extraTime - Date.now());
    } catch (err) {
      swalError('Failed to update court occupancy. Please try again.');
    }
  }, [updateRequest, timers, fetchCourtsData]);

  //get location functions
  const getLocation = useCallback(async() => { //async call because it depends on the user
    if(navigator.geolocation) {
      try {
        const position = await new Promise((resolve, reject) => { //{
        // wait to get the result from the user
          navigator.geolocation.getCurrentPosition(resolve, reject, {
            enableHighAccuracy: true,
            maximumAge: 60000, // DELETE THIS, 1 minute cache
          });
        });

        return { latitude: position.coords.latitude, longitude: position.coords.longitude };
      } catch (error) {}
    }

    return null;
  }, []);

  // Calculate distance between two coordinates using geolib's getDistance (returns meters)
  const calculateDistance = useCallback((personLat, personLon, courtLat, courtLon) => {
    return getDistance({ latitude: personLat, longitude: personLon }, { latitude: courtLat, longitude: courtLon });
  }, []);

  const closeEnough = useCallback((court, userLocation) => {
    if(!userLocation) return false; // if we don't have user location, they can't be close enough
    const distance = calculateDistance(userLocation.latitude, userLocation.longitude, court.latitude, court.longitude);

    return distance <= court.max_meters;
  }, [calculateDistance]);

  const handleToggleOccupied = useCallback(async (id) => {
    if (isSubmittingRef.current) return;
    isSubmittingRef.current = true;

    try {
    const court = courts.find(court => court.id === id);
    if (!court) return;

    let location = await getLocation(); //wait for the location
    let distance = 1e9;
    if(location != null) distance = calculateDistance(location.latitude, location.longitude, court.latitude, court.longitude);

    let force_through = false;
    let allowPress = closeEnough(court, location);
    if(!allowPress) { 
      //greater than 200 meters or can not get location
      let distanceKm = Math.round(distance / 100) / 10;
      if(court.enable_geofence) {
        //enable_geofence is true
        if(location != null) {          
          Swal.fire({
            icon: 'warning',
            //title: 'Location Check',
            html: `
              <div>
                Your location appears to be <b>${distanceKm} km</b> from the court.
                <br/><br/>
                Please press <b>Click to Start</b> only when you are at the court.
                <br/><br/>
                If you're already at the court, enable precise location access and try again.
              </div>           
            `,
            showConfirmButton: false,    //do not show ok button
            showCloseButton: true,
          });
        } else {
          //swalError('Failed to get your location. Please allow location access in setting and try again.');
          Swal.fire({
            icon: 'warning',
            title: '',
            html: `
              <div>
                We couldn't verify that you're at the court.
                <br/><br/>
                Please scan the QR code with your phone's Camera app and turn on location access.
              </div>
            `,
            showConfirmButton: false,    //do not show ok button
            showCloseButton: true,
          });
        }
        return;
      } 
      else {
        //enable_geofence is false
        //greater than 200 meters or can not get location
        let res;
        if(location != null) {
          if (distanceKm < 3) {
            //distance is from 200 meters to *km
            res = await Swal.fire({
              icon: 'info',
              //title: 'Location Check',
              html: `
                <div>
                  Your location appears to be about <b>${distanceKm} km</b> from the court.
                  <br/><br/>
                  Would you like to start anyway?
                </div>            
              `,
              confirmButtonText: "Start Anyway",
              showCloseButton: true,
            });
            force_through = res.isConfirmed;
          }
          else {
            //For anyone with location servcies enabled and the distance is greater than * km, we should deny the usage to show our system is reliable. 
            res = await Swal.fire({
              icon: 'warning',
              //title: 'Location Check',
              html: `
                <div>
                  Your location appears to be <b>${distanceKm} km</b> from the court.
                  <br/><br/>
                  Please press <b>Click to Start</b> only when you are at the court.
                </div>           
              `,
              showConfirmButton: false,    //do not show ok button
              showCloseButton: true,
            });
            force_through = false;
          }
        }else {
          res = await Swal.fire({
            icon: 'info',
            title: '',
            html: `
              <div>
                We couldn't verify that you're at the court.
                <br/><br/>
                If you're already at the court, you may choose <b>Start Anyway</b>.
                <br/><br/>
                For the best experience, scan the QR code with your phone's Camera app and turn on location access.
              </div>
            `,
            confirmButtonText: "Start Anyway",
            showCloseButton: true,
          });
          force_through = res.isConfirmed;
        }
      }
    }

    if(allowPress || force_through) {
      const labels = court.court_labels;

      if(labels.length > 0){
        //turn html into a button conatiner
        let html = '<div class="label-button-container">';
        for(let i = 0; i < labels.length; i++){
          html += `<button class="label-button" id="${i}">${labels[i]}</button>`;
        }
        html += '</div>';

        Swal.fire({
          icon: 'question',
          title: `Which court are you playing at?`,
          html: html,
          showConfirmButton: false,
          showCloseButton: true,
          didOpen: () => {
            const container = Swal.getHtmlContainer();
            container.addEventListener('click', async (event) => {
              const btn = event.target; // Get the clicked element
              if (btn.tagName === 'BUTTON') {
                const index = Number(btn.id);
                const court_label = labels[index];

                console.log(`User selected court label: ${court_label}`); // Debugging
                Swal.close();
                await updateCourts(court, court_label, distance); // Pass the court label directly
              }
            });
          },
        });
      }else{
        await updateCourts(court, null, distance); // no label
      }
    }
    } finally {
      isSubmittingRef.current = false;
    }
  }, [courts, closeEnough, calculateDistance, getLocation, updateCourts]);// timers, ]);

  //WebSocket connection for listening
  useSocket(joinApi(), (data) => {
    // Only update if the event is for the court we're viewing
    if (data.court_abbrev === abbreviation) {
      setCourts(data.tables || []);
    }
  });

  useEffect(() => {
    const timers = JSON.parse(localStorage.getItem('courtTimers') || '{}');

    //filter out expired timers
    const entries = Object.entries(timers);
    for(const [courtId, timerData] of entries) {
      if(timerData.expireTime + timerData.extraTime <= Date.now()) {
        delete timers[courtId];
      }
    }
    
    setTimers(timers);
    localStorage.setItem('courtTimers', JSON.stringify(timers));
  }, []);

  // Initial data fetch
  useEffect(() => {
    fetchCourtsData();
  }, [fetchCourtsData]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      // Clear any scheduled timeouts on unmount
      try {
        Object.values(timerIdsRef.current).forEach(timerId => clearTimeout(timerId));
      } catch (e) {}
      timerIdsRef.current = {};
    };
  }, []);

  // Define the missing functions
  const handleEdit = id => {
    const [court] = courts.filter(court => court.id === id);
    setselectedCourt(court);
    setIsEditing(true);
  };

  const handleDelete = id => {
    Swal.fire({
      icon: 'warning',
      title: 'Are you sure?',
      text: "You won't be able to revert this!",
      showCancelButton: true,
      confirmButtonText: 'Yes, delete it!',
      cancelButtonText: 'No, cancel!',
      customClass: { cancelButton: 'cancel-button' },
      buttonsStyling: false,
      showCloseButton: true,
    }).then(result => {
      if (result.value) {
        const [court] = courts.filter(court => court.id === id);

        Swal.fire({
          icon: 'success',
          title: 'Deleted!',
          text: `${court.court_name} ${court.address}'s data has been deleted.`,
          showConfirmButton: false,
          timer: 1500,
          showCloseButton: true,
        });

        const courtsCopy = courts.filter(court => court.id !== id);
        localStorage.setItem('courts_data', JSON.stringify(courtsCopy));
        setCourts(courtsCopy);
      }
    });
  };

  return (
    <div className="container">
      {!isAdding && !isEditing && (
        <>
          <Header
            isAuthenticated={isAuthenticated}
            setIsAdding={setIsAdding}
            setIsAuthenticated={setIsAuthenticated}
            setShowLogin={setShowLogin}
            searchQuery={searchQuery}
            setSearchQuery={setSearchQuery}
            court_abbrev={court_abbrev}
          />
          <Table
            courts={courts}
            isAuthenticated={isAuthenticated}
            handleEdit={handleEdit}
            handleDelete={handleDelete}
            handleToggleOccupied={handleToggleOccupied}
            timers={timers}
            isMobile={window.innerWidth <= 768}
          />
        </>
      )}
      {isAdding && (
        <Add
          courts={courts}
          setCourts={setCourts}
          setIsAdding={setIsAdding}
        />
      )}
      {isEditing && (
        <Edit
          courts={courts}
          selectedCourt={selectedCourt}
          setCourts={setCourts}
          setIsEditing={setIsEditing}
        />
      )}
    </div>
  );
};

export default Dashboard;
