import { useEffect, useRef } from 'react';
import io from 'socket.io-client';

//Listening for socket.io events
export function useSocket(url, onCourtsUpdated) {
  const socketRef = useRef(null);
  const callbackRef = useRef(onCourtsUpdated);

  // Keep callback ref up to date without reconnecting the socket
  useEffect(() => {
    callbackRef.current = onCourtsUpdated;
  }, [onCourtsUpdated]);

  useEffect(() => {
    socketRef.current = io(url, {
      reconnection: true,
      reconnectionAttempts: Infinity,
      reconnectionDelay: 1000,
      reconnectionDelayMax: 5000,
    });

    socketRef.current.on('courtsUpdated', (data) => {
      if (callbackRef.current) callbackRef.current(data);
    });

    return () => {
      if (socketRef.current) {
        socketRef.current.disconnect();
      }
    };
  }, [url]);

  return socketRef;
}