import React, { useRef, useEffect, useState } from 'react';
import 'bootstrap-icons/font/bootstrap-icons.css';
import Chart from 'chart.js/auto';

const renderCourtButton = (court, handleToggleOccupied, timers, isMobile) => {
  const anyActive = Object.values(timers).some(
    t => Date.now() < (t.expireTime + t.extraTime)
  );
  
  if(anyActive || !isMobile) return <div style={{ minHeight: '60px' }} />;
  
  return (
    <button
      onClick={(e) => {
        e.stopPropagation();
        handleToggleOccupied(court.id, e);
      }}
      className="button"
    >
      Click to Start
    </button>
  );
};

const getRoundedHour = (date, timezone) => {
  if (timezone) {
    const parts = new Intl.DateTimeFormat('en-US', {
      timeZone: timezone,
      hour: 'numeric',
      minute: 'numeric',
      hour12: false,
    }).formatToParts(date);
    const hour = Number(parts.find(p => p.type === 'hour')?.value || 0);
    const minute = Number(parts.find(p => p.type === 'minute')?.value || 0);
    const roundedHour = hour + (minute >= 30 ? 1 : 0);
    return roundedHour === 24 ? 0 : roundedHour;
  }
  const roundedHour = date.getHours() + (date.getMinutes() >= 30 ? 1 : 0);
  return roundedHour === 24 ? 0 : roundedHour;
};

const getDayTypeDivisor = (dayType) => dayType === 'weekend' ? 2 : 5;

const buildHourlyData = (popularTimes = [], dayType = 'weekday', timezone) => {
  const startHour = 7;
  const endHour = 22;
  const divisor = getDayTypeDivisor(dayType);

  const hourly = Array.from(
    { length: endHour - startHour + 1 },
    (_, i) => ({
      hour: `${startHour + i}:00`,
      sessions: 0,
    })
  );

  popularTimes.forEach(row => {
    const date = new Date(row.started_at);
    if (Number.isNaN(date.getTime())) return;

    const hour = getRoundedHour(date, timezone);
    if(hour >= startHour && hour <= endHour) {
      hourly[hour - startHour].sessions += 1 / divisor;
    }
  });

  return hourly;
};

const popularTimesByDay = (popularTimes = [], dayType, timezone) => {
  return popularTimes.filter(row => {
    const date = new Date(row.started_at);
    if (Number.isNaN(date.getTime())) return false;

    let day;
    if (timezone) {
      const parts = new Intl.DateTimeFormat('en-US', {
        timeZone: timezone,
        weekday: 'short',
      }).formatToParts(date);
      const weekday = parts.find(p => p.type === 'weekday')?.value;
      const isWeekend = weekday === 'Sat' || weekday === 'Sun';
      return dayType === 'weekend' ? isWeekend : !isWeekend;
    }

    day = date.getDay();
    const isWeekend = day === 0 || day === 6;

    return dayType === 'weekend' ? isWeekend : !isWeekend;
  });
};

const getCurrentDayType = (timezone) => {
  if (timezone) {
    const parts = new Intl.DateTimeFormat('en-US', {
      timeZone: timezone,
      weekday: 'short',
    }).formatToParts(new Date());
    const weekday = parts.find(p => p.type === 'weekday')?.value;
    return weekday === 'Sat' || weekday === 'Sun' ? 'weekend' : 'weekday';
  }
  const day = new Date().getDay();
  return day === 0 || day === 6 ? 'weekend' : 'weekday';
};

const NOTE_TAGS = new Set(['h1', 'li']);

const getNoteTag = (note) => {
  const html = note.notes || '';
  const text = html.replace(/<[^>]*>/g, '').trim().toLowerCase();
  const tag = String(note.place || note.type || 'li')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]/g, '');

  if (/^<h1[\s>]/i.test(html) || text === 'how to use courtinuse') {
    return 'h1';
  }

  return NOTE_TAGS.has(tag) ? tag : 'li';
};

const getNoteHtml = (note, tag) => {
  const html = note.notes || '';

  if (tag === 'h1') {
    return html.replace(/^<h1[^>]*>/i, '').replace(/<\/h1>$/i, '');
  }

  return html;
};

const renderNoteContent = (note, tag) => ({
  dangerouslySetInnerHTML: { __html: getNoteHtml(note, tag) },
});

const renderNotes = (notes) => {
  const elements = [];
  let listItems = [];

  const flushList = () => {
    if (listItems.length === 0) return;

    elements.push(
      <ul key={`list-${elements.length}`}>
        {listItems.map(note => (
          <li key={note.id} {...renderNoteContent(note, 'li')} />
        ))}
      </ul>
    );
    listItems = [];
  };

  notes.forEach(note => {
    const tag = getNoteTag(note);

    if (tag === 'li') {
      listItems.push(note);
      return;
    }

    flushList();

    const NoteTag = tag;
    elements.push(<NoteTag key={note.id} {...renderNoteContent(note, tag)} />);
  });

  flushList();
  return elements;
};

const NotesCard = ({ notes }) => {
  const visibleNotes = notes?.filter(note => note.place != null) || [];

  if (!visibleNotes.length) return null;

  return (
    <div className="card notes-card">
      {renderNotes(visibleNotes)}
    </div>
  );
};

const formatDisplayTime = (startedAt, displayTimeType, timezone) => {
  const date = new Date(startedAt);
  if (Number.isNaN(date.getTime())) return '—';

  const tzOption = timezone ? { timeZone: timezone } : {};

  if (displayTimeType === 1 && date > new Date(Date.now() - 60 * 60 * 1000)) {
    return `~${date.toLocaleTimeString([], {
      hour: 'numeric',
      ...tzOption,
    })}`;
  }

  return date.toLocaleTimeString([], {
    hour: '2-digit',
    minute: '2-digit',
    ...tzOption,
  });
};

const VERY_BUSY_PERCENTAGE = 50;

const getBusyLevel = (value, maxSessions) => {
  const percentage = maxSessions > 0 ? (value / maxSessions) * 100 : 0;
  return percentage <= VERY_BUSY_PERCENTAGE ? "Occasionally busy" : "Very Busy";
};

const WEATHER_CODES = {
  0: { icon: "bi-sun-fill", color: "#facc15", text: "Clear" },
  1: { icon: "cloud-sun", text: "Mostly Clear" },
  2: { icon: "cloud-sun", text: "Partly Cloudy" },
  3: { icon: "bi-cloud-fill", color: "#94a3b8", text: "Cloudy" },
  45: { icon: "bi-cloud-fog2-fill", color: "#94a3b8", text: "Fog" },
  48: { icon: "bi-cloud-fog2-fill", color: "#94a3b8", text: "Fog" },
  51: { icon: "🌦️", text: "Light Drizzle" },
  53: { icon: "🌦️", text: "Drizzle" },
  55: { icon: "🌧️", text: "Heavy Drizzle" },
  61: { icon: "🌦️", text: "Light Rain" },
  63: { icon: "🌧️", text: "Rain" },
  65: { icon: "🌧️", text: "Heavy Rain" },
  71: { icon: "🌨️", text: "Snow" },
  73: { icon: "🌨️", text: "Snow" },
  75: { icon: "🌨️", text: "Heavy Snow" },
  80: { icon: "🌦️", text: "Rain Showers" },
  81: { icon: "🌧️", text: "Rain Showers" },
  82: { icon: "🌧️", text: "Heavy Showers" },
  95: { icon: "⛈️", text: "Thunderstorm" },
};

const getWeatherDescription = (weatherCode) => {
  return WEATHER_CODES[weatherCode] || { icon: "bi-thermometer-half", color: "#64748b", text: "Weather" };
};

const renderWeatherIcon = (weather) => {
  if (weather.icon === "cloud-sun") {
    return (
      <span className="weather-layered-icon" aria-hidden="true">
        <i className="bi bi-sun-fill weather-layered-sun"></i>
        <i className="bi bi-cloud-fill weather-layered-cloud"></i>
      </span>
    );
  }

  if (!weather.icon.startsWith("bi-")) {
    return <span className="weather-icon" aria-hidden="true">{weather.icon}</span>;
  }

  return (
    <i
      className={`bi ${weather.icon} weather-icon`}
      style={{ color: weather.color }}
      aria-hidden="true"
    ></i>
  );
};

function WeatherStatus({ latitude, longitude }) {
  const [weather, setWeather] = useState(null);

  useEffect(() => {
    if (latitude == null || longitude == null) return;

    const controller = new AbortController();
    const params = new URLSearchParams({
      latitude,
      longitude,
      current: "temperature_2m,weather_code,wind_speed_10m",
    });

    fetch(`https://api.open-meteo.com/v1/forecast?${params}`, {
      signal: controller.signal,
    })
      .then(response => {
        if (!response.ok) throw new Error("Weather request failed");
        return response.json();
      })
      .then(data => {
        const current = data.current;
        if (!current) return;

        const description = getWeatherDescription(current.weather_code);
        setWeather({
          ...description,
          temperature: Math.round(current.temperature_2m),
          windSpeed: Math.round(current.wind_speed_10m),
        });
      })
      .catch(error => {
        if (error.name !== "AbortError") {
          setWeather(null);
        }
      });

    return () => controller.abort();
  }, [latitude, longitude]);

  if (!weather) {
    return <span className="weather-status" title="Weather unavailable">—</span>;
  }

  return (
    <span
      className="weather-status"
      title={`${weather.text}, wind ${weather.windSpeed} km/h`}
      aria-label={`${weather.text}, ${weather.temperature} degrees Celsius, wind ${weather.windSpeed} kilometers per hour`}
    >
      <span className="weather-condition">
        {renderWeatherIcon(weather)}
        <span>{weather.temperature}°C</span>
      </span>
      <span className="weather-metric">
        <i className="bi bi-wind" aria-hidden="true"></i>
        {weather.windSpeed} km/h
      </span>
    </span>
  );
}

function MyChart({ data, maxSessions }) {
  const canvasRef = useRef(null);

  useEffect(() => {
    const ctx = canvasRef.current;
    const myChart = new Chart(ctx, {
      type: 'bar',
      data: data,
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          legend: {
            display: false
          },
    
          tooltip: {
            callbacks: {
              label: (context) => {
                const value = context.raw;
    
                return getBusyLevel(value, maxSessions);
              },

              labelColor: (context) => {
                const value = context.raw;
                const busyLevel = getBusyLevel(value, maxSessions);
          
                if (busyLevel === "Occasionally busy") {
                  return {
                    backgroundColor: '#f59e0b'
                  };
                }

                return {
                  backgroundColor: '#ef4444'
                };
              }
            }
          }
        },
    
        scales: {
          x: {
            grid: {
              display: false
            }
          },
          y: {
            suggestedMax: maxSessions,
            ticks: {
              display: false
            },
            border: {
              display: false
            },
            grid: {
              display: true
            }
          }
        }
      }
    });

    return () => myChart.destroy();
  }, [data, maxSessions]);

  return <canvas ref={canvasRef} />;
}

const Table = ({ courts, handleToggleOccupied, timers, isMobile}) => {
  const [expanded, setExpanded] = useState({});
  const [popularDay, setPopularDay] = useState({});
  const [graphDay, setGraphDay] = useState({});

  return (
    <div>
      <div className="card-container">
        {courts.length > 0 ? (
          courts.map((court) => {
            const selectedDayType = popularDay[court.id] || getCurrentDayType(court.timezone);
            const filteredPopularTimes = popularTimesByDay(court.popular_times || [], selectedDayType, court.timezone);
            const hourlyData = buildHourlyData(filteredPopularTimes, selectedDayType, court.timezone);
            const weekdayHourlyData = buildHourlyData(popularTimesByDay(court.popular_times || [], 'weekday', court.timezone), 'weekday', court.timezone);
            const weekendHourlyData = buildHourlyData(popularTimesByDay(court.popular_times || [], 'weekend', court.timezone), 'weekend', court.timezone);
            const maxSessions = Math.max(
              1,
              ...weekdayHourlyData.map(d => d.sessions),
              ...weekendHourlyData.map(d => d.sessions)
            );
            const currentHourLabel = `${getRoundedHour(new Date(), court.timezone)}:00`;

            const chartData = {
              labels: hourlyData.map(d => d.hour),
              datasets: [
                {
                  label: "Sessions",
                  data: hourlyData.map(d => d.sessions),
                  borderColor: "#3b82f6",
                  borderRadius: 6,
                  backgroundColor: hourlyData.map(d => d.hour === currentHourLabel ? "#CF5534" : "#c8e53f"), //#665FD1
                  tension: 0.3,
                  barPercentage: 1.0,
                  fill: true,
                }
              ]
            };

            return (
              <div key={court.id}>
                <div className="card">
                  <div className="card-header">
                    <div className="card-name">
                      <h2><b>{court.court_name}</b></h2>
                      <h3>
                        {court.court_capacity} Tennis Court{court.court_capacity > 1 ? 's' : ''}
                      </h3>
                    </div>

                    <div className="card-status">
                      <span 
                        className="status-label"
                        style={{
                          background: court.occupied === court.court_capacity ? '#FC806A' : court.occupied + 1 === court.court_capacity && court.occupied > 0 ? '#FFF3B0': '#DBFCCC',
                        }}
                      >
                        <span className="status-label">
                          <span className={`status-dot ${ court.occupied === court.court_capacity ? 'is-unavailable' : court.occupied + 1 === court.court_capacity && court.occupied > 0 ? 'is-busy' : 'is-available' }`}></span>
                          {`${court.occupied} court${court.occupied !== 1 ? 's' : ''} in use`}
                        </span>
                      </span>
                      <WeatherStatus latitude={court.latitude} longitude={court.longitude} />
                    </div>
                  </div>

                  <div className="card-action">
                    <div className="last-used-group">
                      <i className="bi bi-clock" style={{ fontSize: '2rem' }}></i>

                      <div>
                        <span>Last Used</span>
                        <div>
                          {court.today_times?.[0] ? (
                            formatDisplayTime(court.today_times[0].started_at, court.display_time_type, court.timezone)
                          ) : (
                            '—'
                          )}
                        </div>
                      </div>
                    </div>

                    <div>
                      {renderCourtButton(court, handleToggleOccupied, timers, isMobile)}
                    </div>
                  </div>
                  
                  {court.display_time_type !== 2 && (
                    <div>
                      <div className="details-header"
                        onClick={() =>
                          setExpanded(prev => ({
                            ...prev,
                            [court.id]: !prev[court.id]
                          }))
                        }
                      >
                        Usage Details
                        {expanded[court.id] ? (<i className="bi bi-caret-down-fill"></i>) : (<i className="bi bi-caret-up-fill"></i>)}
                      </div>

                      {!expanded[court.id] && (
                        <div className="details-content">
                          <div className="details-column">
                            <p>Current Usage</p>
                            {court.occupied > 0 ? court.recent_times.slice(0, court.court_capacity).map((session, i) => (
                              <div key={i}>
                                {formatDisplayTime(session.started_at, court.display_time_type, court.timezone)}
                                {court.court_capacity > 1 && ` on ${session.court_label}`}
                              </div>
                            )) : <div>—</div>}
                          </div>
                          
                          <div className="details-column">
                            <p>Usage Today</p>
                            {court.today_times?.length > 0 ? court.today_times.map((session, i) => {
                              const hoursAgo = (Date.now() - new Date(session.started_at).getTime()) / 3600000;
                              const opacity = 1 - (hoursAgo / 24) * 0.8;
                              const isCurrentlyPlaying = i < court.occupied;
                              return (
                                <div key={i} style={{ opacity }}>
                                  {formatDisplayTime(session.started_at, isCurrentlyPlaying ? court.display_time_type : 0, court.timezone)}
                                  {court.court_capacity > 1 && ` on ${session.court_label}`}
                                </div>
                              );
                            }) : <div>—</div>}
                          </div>
                        </div>
                      )}
                    </div>
                  )}
                </div>

                <NotesCard notes={court.solo_notes} />
                
                <NotesCard notes={court.all_notes} />

                <div className="card" style={{ height: "350px", padding: "0 16px"}}>
                  <div className="graph-header">
                    <div className="graph-title">
                      <i className="bi bi-people-fill" style={{ fontSize: '1.5rem' }}></i>
                      <h2>Popular Times</h2>
                    </div>

                    <div className="graph-dropdown">
                      <button
                        className="graph-dropdown-button"
                        onClick={() =>
                          setGraphDay(prev => ({
                            ...prev,
                            [court.id]: !prev[court.id]
                          }))
                        }
                      >
                        {selectedDayType === 'weekend' ? 'Weekend' : 'Weekday'}
                        <i className={`bi ${graphDay[court.id] ? 'bi-caret-up-fill' : 'bi-caret-down-fill'}`}></i>
                      </button>

                      {graphDay[court.id] && (
                        <div className="graph-dropdown-menu">
                          {['weekday', 'weekend'].map(dayType => (
                            <button
                              key={dayType}
                              type="button"
                              className={selectedDayType === dayType ? 'is-active' : ''}
                              onClick={() => {
                                setPopularDay(prev => ({
                                  ...prev,
                                  [court.id]: dayType
                                }));
                                setGraphDay(prev => ({
                                  ...prev,
                                  [court.id]: false
                                }));
                              }}
                            >
                              {dayType === 'weekend' ? 'Weekend' : 'Weekday'}
                            </button>
                          ))}
                        </div>
                      )}
                    </div>
                  </div>
                  <div style={{ height: "250px" }}>
                    <MyChart data={chartData} maxSessions={maxSessions} />
                  </div>
                </div>
              </div>
            );
          })
        ) : (
          <div className="card">
            <h2>No courts</h2>
          </div>
        )}
      </div>
    </div>
  );
};

export default Table;
